"use client";

import { useEffect, useState } from "react";

export function TtsCard() {
  const [text, setText] = useState("Hola, esta es una prueba con la voz Eve.");
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    return () => {
      if (audioUrl) {
        URL.revokeObjectURL(audioUrl);
      }
    };
  }, [audioUrl]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!text.trim()) {
      setError("Escribe algo de texto.");
      return;
    }
    setError(null);
    setIsLoading(true);
    if (audioUrl) {
      URL.revokeObjectURL(audioUrl);
      setAudioUrl(null);
    }
    try {
      const res = await fetch("/api/xai/tts", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: text.trim() }),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data?.error || "No se pudo generar audio");
      }
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      setAudioUrl(url);
    } catch (err) {
      console.error(err);
      setError("Error generando audio. Reintenta.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section className="py-12 px-6 bg-gray-50">
      <div className="max-w-5xl mx-auto grid gap-6 lg:grid-cols-[1fr_0.9fr] items-start">
        <div className="space-y-3">
          <p className="text-sm uppercase tracking-[0.2em] text-lime-600">
            Text-to-Speech
          </p>
          <h2 className="text-3xl font-semibold text-black">
            Voz Eve on-demand (mp3)
          </h2>
          <p className="text-gray-700">
            Genera audio bajo clic y reprodÃºcelo en la pÃ¡gina. La clave se usa
            solo en el backend; el navegador recibe el mp3 listo para sonar.
          </p>
          <ul className="text-sm text-gray-600 list-disc pl-5 space-y-1">
            <li>Formato: mp3, 44.1 kHz, 128 kbps.</li>
            <li>Ideal para botones de reproducir/leer en la web.</li>
            <li>Si quieres otro idioma/voz, cambia los parÃ¡metros en el endpoint.</li>
          </ul>
        </div>

        <div className="rounded-2xl border border-gray-200 bg-white p-6 shadow-sm space-y-4">
          <form
            onSubmit={handleGenerate}
            className="space-y-3"
            suppressHydrationWarning
          >
            <label className="text-sm font-semibold text-gray-900">
              Texto a leer
            </label>
            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              className="w-full rounded-xl border border-gray-300 px-4 py-3 text-gray-900 focus:border-lime-500 focus:outline-none"
              rows={4}
              placeholder="Escribe el texto que quieras convertir a audio..."
              suppressHydrationWarning
            />
            <button
              type="submit"
              disabled={isLoading}
              suppressHydrationWarning
              className="w-full rounded-xl bg-lime-500 px-4 py-3 font-bold text-black hover:bg-lime-400 transition disabled:opacity-60"
            >
              {isLoading ? "Generando..." : "Generar y reproducir"}
            </button>
          </form>
          {error && <p className="text-sm text-red-500">{error}</p>}
          {audioUrl ? (
            <div className="space-y-2">
              <audio controls src={audioUrl} className="w-full" />
              <p className="text-xs text-gray-500">
                El audio se genera bajo demanda y no guarda la API key en el cliente.
              </p>
            </div>
          ) : (
            <div className="rounded-xl border border-dashed border-gray-300 px-4 py-10 text-center text-gray-500">
              AÃºn no hay audio. Genera para reproducirlo aquÃ­.
            </div>
          )}
        </div>
      </div>
    </section>
  );
}
